PINYIN_INITIALS = {}
for _ltr, _chars in _GROUPS.items():
    for _c in _chars:
        PINYIN_INITIALS[_c] = _ltr


def first_letters(text):
    """取字符串里所有汉字的拼音首字母拼接，非汉字忽略。"""
    if not text:
        return ""
    res = []
    for ch in str(text):
        ini = PINYIN_INITIALS.get(ch)
        if ini:
            res.append(ini)
    return "".join(res)
